```class Solution {
public:
    int maxPalindromes(string s, int k) {
        int count = 0;
        int len = s.length();
        for (int i = 0; i < len; i++) {
            for (int j = i + k; j < len; j++) {
                int len_diff = j - i;
                if (len_diff >= k && s.substr(i, k) == s.substr(j, k) && isPalindrome(s.substr(i, len_diff))) {
                    count++;
                }
            }
        }
        return count;
    }

    bool isPalindrome(string s) {
        int len = s.length();
        for (int i = 0; i < len / 2; i++) {
            if (s[i] != s[len - i - 1]) {
                return false;
            }
        }
        return true;
    }
};
